import { ReportesService } from '../../../../core/services/reportes.service';
import { ArchivoProtegidoService } from '../../../../core/services/archivo-protegido.service';
import { ToastService } from '../../../../core/services/toast.service';
import { ConfirmModalComponent } from '../../../../core/components/confirm-modal/confirm-modal.component';
import { formatBytes, getFileIcon, getCleanFileType, getFileExtension } from '../../../../core/utils/file.utils';
import { getSubscriptionClass, formatNiveles } from '../../../../core/utils/subscription.utils';

@Component({
  selector: 'app-curso-detalle',
  standalone: true,
  imports: [
    CommonModule,
    RouterModule,
    FormsModule,
    ReactiveFormsModule,
    ConfirmModalComponent
  ],
  templateUrl: './curso-detalle.component.html',
  styleUrls: ['./curso-detalle.component.css']
})
export class CursoDetalleComponent implements OnInit {
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private cursoService = inject(CursoService);
  private moduloService = inject(ModuloService);
  private matriculaService = inject(MatriculaService);
  private alumnoService = inject(AlumnoService);
  private fb = inject(FormBuilder);
  private videoService = inject(VideoService);
  private materialService = inject(MaterialService);
  private reportesService = inject(ReportesService);
  private archivoProtegidoService = inject(ArchivoProtegidoService);
  private toastService = inject(ToastService);
  private authService = inject(AuthService);

  isDocente = false;

  exportarMatriculasCSV(): void {
    this.reportesService.exportarMatriculas().subscribe({
      error: (err) => {
        console.error('Error al exportar matrículas:', err);
      }
    });
  }

  cursoId!: number;
  curso: CursoResponse | null = null;
  modulos: ModuloResponse[] = [];

  // Active tab
  activeTab: 'modulos' | 'matriculas' = 'modulos';

  // Inline dynamic accordion properties
  expandedModuloId: number | null = null;
  videosMap: { [key: number]: VideoResponse[] } = {};
  materialesMap: { [key: number]: MaterialResponse[] } = {};

  // Inline forms toggles and inputs
  videoFormOpenMap: { [key: number]: boolean } = {};
  materialFormOpenMap: { [key: number]: boolean } = {};

  nuevoVideoTitulo = '';
  nuevoVideoUrl = '';
  nuevoVideoDesc = '';
  isAddingVideo = false;

  nuevoMaterialNombre = '';
  nuevoMaterialFile: File | null = null;
  isUploadingMaterial = false;

  // Matriculas
  matriculas: MatriculaResponse[] = [];
  alumnos: AlumnoResponse[] = [];
  alumnosDisponibles: AlumnoResponse[] = [];
  showMatriculaModal = false;
  isMatriculaSubmitting = false;
  matriculaErrorMsg = '';
  selectedAlumnoId: number | null = null;

  // Confirm modal controls
  showConfirmModal = false;
  confirmModalType: 'success' | 'danger' | 'info' | 'warning' = 'warning';
  confirmModalTitle = '';
  confirmModalMessage = '';
  pendingAction: (() => void) | null = null;

  // Modals
  showModuloModal = false;
  showEditCourseModal = false;
  isEditModuloMode = false;
  isModuloSubmitting = false;
  isCourseSubmitting = false;

  // Selected for edits
  selectedModulo: ModuloResponse | null = null;

  // Errors
  moduloErrorMsg = '';
  courseErrorMsg = '';

  // Forms
  moduloForm: FormGroup = this.fb.group({
    nombre: ['', [Validators.required, Validators.minLength(3), Validators.maxLength(200)]],
    descripcion: ['', [Validators.required, Validators.minLength(10), Validators.maxLength(2000)]],
    orden: [1, [Validators.required, Validators.min(1), Validators.max(999)]],
    estado: [true]
  });

  selectedSuscripcionIds: number[] = [];

  courseForm: FormGroup = this.fb.group({
    nombre: ['', [Validators.required, Validators.minLength(3), Validators.maxLength(200)]],
    descripcion: ['', [Validators.required, Validators.minLength(10), Validators.maxLength(2000)]],
    imagenPortada: ['', [Validators.pattern('^https?:\\/\\/.+$')]],
    estado: [true]
  });

  ngOnInit(): void {
    this.authService.getProfile().subscribe(user => {
      if (user && user.rol === 'DOCENTE') {
        this.isDocente = true;
        this.activeTab = 'modulos';
      }
    });

    this.route.paramMap.subscribe(params => {
      const idParam = params.get('id');
      if (idParam) {
        this.cursoId = Number(idParam);
        this.loadCourseData();
      } else {
        this.router.navigate([this.isDocente ? '/dashboard/mis-cursos-docente' : '/dashboard/cursos']);
      }
    });
  }

  confirmAction(): void {
    if (this.pendingAction) {
      this.pendingAction();
    }
  }

  loadCourseData(): void {
    this.cursoService.obtenerCurso(this.cursoId).subscribe({
      next: (data) => {
        try {
          this.curso = data;
          this.loadModulos();
          this.loadMatriculas();
        } catch (e: any) {
          console.error('Error al asignar datos de curso:', e);
          this.toastService.error('Excepción al cargar detalles: ' + e.message);
        }
      },
      error: (err) => {
        console.error('Error al obtener curso', err);
        const errMsg = err.error?.message || err.message || 'Error desconocido';
        this.toastService.error('Error al obtener los detalles del curso: ' + errMsg);
        this.router.navigate([this.isDocente ? '/dashboard/mis-cursos-docente' : '/dashboard/cursos']);
      }
    });
  }

  loadModulos(): void {
    try {
      this.moduloService.listarModulosPorCurso(this.cursoId).subscribe({
        next: (data) => {
          this.modulos = data;
        },
        error: (err) => {
          console.error('Error al listar módulos', err);
          this.toastService.error('Error al cargar módulos: ' + (err.error?.message || err.message));
        }
      });
    } catch (e: any) {
      console.error('Excepción en loadModulos:', e);
      this.toastService.error('Excepción en carga de módulos: ' + e.message);
    }
  }

  loadMatriculas(): void {
    try {
      this.matriculaService.listarMatriculados(this.cursoId).subscribe({
        next: (data) => {
          this.matriculas = data;
        },
        error: (err) => {
          console.error('Error al listar matrículas', err);
          this.toastService.error('Error al cargar matrículas: ' + (err.error?.message || err.message));
        }
      });
    } catch (e: any) {
      console.error('Excepción en loadMatriculas:', e);
      this.toastService.error('Excepción en carga de matrículas: ' + e.message);
    }
  }

  // Tab switching
  setTab(tab: 'modulos' | 'matriculas'): void {
    this.activeTab = tab;
    if (tab === 'matriculas' && this.matriculas.length === 0) {
      this.loadMatriculas();
    }
  }

  // ====== MATRICULA ACTIONS ======
  openMatriculaModal(): void {
    this.matriculaErrorMsg = '';
    this.selectedAlumnoId = null;
    this.isMatriculaSubmitting = false;

    // Load all alumnos and filter out already enrolled
    this.alumnoService.listarAlumnos().subscribe({
      next: (data) => {
        this.alumnos = data;
        const enrolledIds = new Set(this.matriculas.map(m => m.usuarioId));
        this.alumnosDisponibles = this.alumnos.filter(a => !enrolledIds.has(a.id) && a.estado);
        this.showMatriculaModal = true;
      },
      error: (err) => {
        console.error('Error al cargar alumnos', err);
      }
    });
  }

  closeMatriculaModal(): void {
    this.showMatriculaModal = false;
    this.isMatriculaSubmitting = false;
  }

  onMatriculaSubmit(): void {
    if (!this.selectedAlumnoId) {
      this.matriculaErrorMsg = 'Selecciona un alumno.';
      return;
    }

    this.isMatriculaSubmitting = true;
    this.matriculaErrorMsg = '';

    const req: MatriculaRequest = {
      usuarioId: this.selectedAlumnoId,
      cursoId: this.cursoId
    };

    this.matriculaService.matricularAlumno(req).subscribe({
      next: () => {
        this.loadMatriculas();
        this.toastService.success('Alumno matriculado exitosamente en el curso.');
        this.closeMatriculaModal();
      },
      error: (err) => {
        this.isMatriculaSubmitting = false;
        this.matriculaErrorMsg = err.error?.message || 'Error al matricular al alumno.';
        this.toastService.error(this.matriculaErrorMsg);
      }
    });
  }

  toggleMatriculaEstado(matricula: MatriculaResponse): void {
    const nuevoEstado = !matricula.estado;
    const accion = nuevoEstado ? 'Reactivar' : 'Dar de Baja';
    
    this.confirmModalType = nuevoEstado ? 'success' : 'danger';
    this.confirmModalTitle = `¿${accion} Matrícula?`;
    this.confirmModalMessage = `¿Estás seguro de que deseas ${accion.toLowerCase()} la matrícula del alumno ${matricula.alumnoNombres} ${matricula.alumnoApellidos}?`;
    
    this.pendingAction = () => {
      this.matriculaService.cambiarEstado(matricula.id, nuevoEstado).subscribe({
        next: () => {
          matricula.estado = nuevoEstado;
          this.toastService.success(`Matrícula de ${matricula.alumnoNombres} ${nuevoEstado ? 'reactivada' : 'dada de baja'} exitosamente.`);
          this.showConfirmModal = false;
        },
        error: (err) => {
          this.toastService.error(err.error?.message || 'Error al cambiar estado de la matrícula.');
          this.showConfirmModal = false;
        }
      });
    };
    
    this.showConfirmModal = true;
  }

  // ====== MODULO ACTIONS ======
  openCreateModuloModal(): void {
    this.isEditModuloMode = false;
    this.moduloErrorMsg = '';
    this.selectedModulo = null;
    this.moduloForm.reset({
      nombre: '',
      descripcion: '',
      orden: this.modulos.length + 1,
      estado: true
    });
    this.showModuloModal = true;
  }

  openEditModuloModal(modulo: ModuloResponse): void {
    this.isEditModuloMode = true;
    this.moduloErrorMsg = '';
    this.selectedModulo = modulo;
    this.moduloForm.patchValue({
      nombre: modulo.nombre,
      descripcion: modulo.descripcion,
      orden: modulo.orden,
      estado: modulo.estado
    });
    this.showModuloModal = true;
  }

  closeModuloModal(): void {
    this.showModuloModal = false;
    this.isModuloSubmitting = false;
  }

  toggleModuloEstado(modulo: ModuloResponse): void {
    const nuevoEstado = !modulo.estado;
    const accion = nuevoEstado ? 'Activar' : 'Desactivar';
    
    this.confirmModalType = nuevoEstado ? 'success' : 'warning';
    this.confirmModalTitle = `¿${accion} Módulo?`;
    this.confirmModalMessage = `¿Estás seguro de que deseas ${accion.toLowerCase()} el módulo "${modulo.nombre}"?`;
    
    this.pendingAction = () => {
      this.moduloService.cambiarEstado(modulo.id, nuevoEstado).subscribe({
        next: () => {
          modulo.estado = nuevoEstado;
          this.toastService.success(`Módulo "${modulo.nombre}" ${nuevoEstado ? 'activado' : 'desactivado'} exitosamente.`);
          this.showConfirmModal = false;
        },
        error: (err) => {
          this.toastService.error(err.error?.message || 'Error al cambiar estado del módulo.');
          this.showConfirmModal = false;
        }
      });
    };
    
    this.showConfirmModal = true;
  }

  onModuloSubmit(): void {
    if (this.moduloForm.invalid) {
      this.moduloForm.markAllAsTouched();
      this.toastService.warning('Por favor complete todos los campos requeridos del módulo correctamente.');
      return;
    }

    this.isModuloSubmitting = true;
    this.moduloErrorMsg = '';

    const req: ModuloRequest = {
      cursoId: this.cursoId,
      nombre: this.moduloForm.value.nombre,
      descripcion: this.moduloForm.value.descripcion,
      orden: Number(this.moduloForm.value.orden)
    };

    if (this.isEditModuloMode && this.selectedModulo) {
      this.moduloService.editarModulo(this.selectedModulo.id, req).subscribe({
        next: () => {
          const stateChanged = this.moduloForm.value.estado !== this.selectedModulo!.estado;
          if (stateChanged) {
            this.moduloService.cambiarEstado(this.selectedModulo!.id, this.moduloForm.value.estado).subscribe({
              next: () => {
                this.loadModulos();
                this.toastService.success('Módulo y su estado actualizados con éxito.');
                this.closeModuloModal();
              },
              error: (err) => this.handleModuloError(err)
            });
          } else {
            this.loadModulos();
            this.toastService.success('Módulo modificado con éxito.');
            this.closeModuloModal();
          }
        },
        error: (err) => this.handleModuloError(err)
      });
    } else {
      this.moduloService.crearModulo(req).subscribe({
        next: () => {
          this.loadModulos();
          this.toastService.success('Módulo creado con éxito.');
          this.closeModuloModal();
        },
        error: (err) => this.handleModuloError(err)
      });
    }
  }

  private handleModuloError(err: any): void {
    this.isModuloSubmitting = false;
    this.moduloErrorMsg = err.error?.message || 'Error al procesar el módulo.';
    this.toastService.error(this.moduloErrorMsg);
  }

  // ====== COURSE EDIT ACTIONS ======
  openEditCourseModal(): void {
    if (!this.curso) return;
    this.courseErrorMsg = '';
    
    this.selectedSuscripcionIds = [];
    if (this.curso.nivelesSuscripcion) {
      if (this.curso.nivelesSuscripcion.includes('BASICO')) this.selectedSuscripcionIds.push(1);
      if (this.curso.nivelesSuscripcion.includes('INTERMEDIO')) this.selectedSuscripcionIds.push(2);
      if (this.curso.nivelesSuscripcion.includes('PREMIUM')) this.selectedSuscripcionIds.push(3);
    }

    this.courseForm.patchValue({
      nombre: this.curso.nombre,
      descripcion: this.curso.descripcion,
      imagenPortada: this.curso.imagenPortada,
      estado: this.curso.estado
    });
    this.showEditCourseModal = true;
  }

  toggleNivel(id: number): void {
    const idx = this.selectedSuscripcionIds.indexOf(id);
    if (idx > -1) {
      if (this.selectedSuscripcionIds.length > 1) {
        this.selectedSuscripcionIds.splice(idx, 1);
      }
    } else {
      this.selectedSuscripcionIds.push(id);
    }
  }

  isNivelSelected(id: number): boolean {
    return this.selectedSuscripcionIds.includes(id);
  }

  closeEditCourseModal(): void {
    this.showEditCourseModal = false;
    this.isCourseSubmitting = false;
  }

  onCourseSubmit(): void {
    if (!this.curso) return;
    if (this.courseForm.invalid) {
      this.courseForm.markAllAsTouched();
      this.toastService.warning('Por favor complete todos los campos requeridos del curso correctamente.');
      return;
    }

    this.isCourseSubmitting = true;
    this.courseErrorMsg = '';

    const req: CursoRequest = {
      nombre: this.courseForm.value.nombre,
      descripcion: this.courseForm.value.descripcion,
      imagenPortada: this.courseForm.value.imagenPortada || '',
      nivelesSuscripcionIds: this.selectedSuscripcionIds
    };

    this.cursoService.editarCurso(this.cursoId, req).subscribe({
      next: () => {
        const stateChanged = this.courseForm.value.estado !== this.curso!.estado;
        if (stateChanged) {
          this.cursoService.cambiarEstado(this.cursoId, this.courseForm.value.estado).subscribe({
            next: () => {
              this.loadCourseData();
              this.toastService.success('Curso y su estado actualizados con éxito.');
              this.closeEditCourseModal();
            },
            error: (err) => this.handleCourseError(err)
          });
        } else {
          this.loadCourseData();
          this.toastService.success('Curso modificado con éxito.');
          this.closeEditCourseModal();
        }
      },
      error: (err) => this.handleCourseError(err)
    });
  }

  private handleCourseError(err: any): void {
    this.isCourseSubmitting = false;
    this.courseErrorMsg = err.error?.message || 'Error al actualizar el curso.';
    this.toastService.error(this.courseErrorMsg);
  }

  formatNiveles = formatNiveles;
  getSubscriptionClass = getSubscriptionClass;

  // --- Dynamic Inline Syllabus Accordion Methods ---
  
  toggleModuloExpansion(moduloId: number): void {
    if (this.expandedModuloId === moduloId) {
      this.expandedModuloId = null;
    } else {
      this.expandedModuloId = moduloId;
      this.cargarContenidoModulo(moduloId);
    }
  }

  cargarContenidoModulo(moduloId: number): void {
    this.videoService.listarVideosPorModulo(moduloId).subscribe({
      next: (data) => this.videosMap[moduloId] = data.sort((a, b) => a.orden - b.orden),
      error: (err) => console.error('Error al cargar videos del módulo', err)
    });
    
    this.materialService.listarMaterialesPorModulo(moduloId).subscribe({
      next: (data) => this.materialesMap[moduloId] = data,
      error: (err) => console.error('Error al cargar materiales del módulo', err)
    });
  }

  // Videos
  agregarVideoInline(moduloId: number): void {
    if (!this.nuevoVideoTitulo || !this.nuevoVideoUrl) {
      this.toastService.warning('Por favor ingrese el título y la URL de YouTube.');
      return;
    }
    this.isAddingVideo = true;
    const req: VideoRequest = {
      moduloId,
      titulo: this.nuevoVideoTitulo,
      descripcion: this.nuevoVideoDesc,
      youtubeUrl: this.nuevoVideoUrl,
      orden: (this.videosMap[moduloId]?.length || 0) + 1
    };
    
    this.videoService.crearVideo(req).subscribe({
      next: () => {
        this.isAddingVideo = false;
        this.nuevoVideoTitulo = '';
        this.nuevoVideoUrl = '';
        this.nuevoVideoDesc = '';
        this.videoFormOpenMap[moduloId] = false;
        this.cargarContenidoModulo(moduloId);
        this.toastService.success('Video agregado exitosamente al módulo.');
      },
      error: (err) => {
        this.isAddingVideo = false;
        this.toastService.error('Error al agregar video: ' + (err.error?.message || err.message));
      }
    });
  }

  toggleVideoEstadoInline(moduloId: number, video: VideoResponse): void {
    const nuevoEstado = !video.estado;
    this.videoService.cambiarEstado(video.id, nuevoEstado).subscribe({
      next: () => {
        video.estado = nuevoEstado;
        this.toastService.success(`Video ${nuevoEstado ? 'activado' : 'desactivado'} exitosamente.`);
      },
      error: (err) => this.toastService.error('Error al cambiar estado del video: ' + err.message)
    });
  }

  // Materials
  onInlineFileSelected(event: any): void {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > 10 * 1024 * 1024) {
        this.toastService.warning('El archivo supera los 10MB permitidos.');
        return;
      }
      this.nuevoMaterialFile = file;
      if (!this.nuevoMaterialNombre) {
        const baseName = file.name.substring(0, file.name.lastIndexOf('.')) || file.name;
        this.nuevoMaterialNombre = baseName;
      }
    }
  }

  subirMaterialInline(moduloId: number): void {
    if (!this.nuevoMaterialFile || !this.nuevoMaterialNombre) {
      this.toastService.warning('Debe ingresar un nombre y seleccionar un archivo.');
      return;
    }
    this.isUploadingMaterial = true;
    this.materialService.subirMaterial(moduloId, this.nuevoMaterialNombre, this.nuevoMaterialFile).subscribe({
      next: () => {
        this.isUploadingMaterial = false;
        this.nuevoMaterialNombre = '';
        this.nuevoMaterialFile = null;
        this.materialFormOpenMap[moduloId] = false;
        this.cargarContenidoModulo(moduloId);
        this.toastService.success('Material de apoyo subido exitosamente.');
      },
      error: (err) => {
        this.isUploadingMaterial = false;
        this.toastService.error('Error al subir material: ' + (err.error?.message || err.message));
      }
    });
  }

  toggleMaterialEstadoInline(moduloId: number, mat: MaterialResponse): void {
    const nuevoEstado = !mat.estado;
    this.materialService.cambiarEstado(mat.id, nuevoEstado).subscribe({
      next: () => {
        mat.estado = nuevoEstado;
        this.toastService.success(`Material ${nuevoEstado ? 'activado' : 'desactivado'} exitosamente.`);
      },
      error: (err) => this.toastService.error('Error al cambiar estado del material: ' + err.message)
    });
  }

  // Helpers
  getFileIcon = getFileIcon;
  getCleanFileType = getCleanFileType;
  formatBytes = formatBytes;

  descargarMaterial(mat: MaterialResponse): void {
    const extension = getFileExtension(mat.tipoArchivo);
    const fileName = mat.nombre.toLowerCase().endsWith(`.${extension}`) ? mat.nombre : `${mat.nombre}.${extension}`;

    this.archivoProtegidoService.descargar(mat.archivoUrl, fileName).subscribe({
      error: (err) => console.error('Error al descargar material:', err)
    });
  }
}
<div class="space-y-8 font-body" *ngIf="curso">

  <!-- Back button -->
  <div class="flex items-center">
    <a 
      [routerLink]="isDocente ? '/dashboard/mis-cursos-docente' : '/dashboard/cursos'" 
      class="flex items-center gap-2 text-[10px] font-black text-slate-500 hover:text-slate-950 dark:text-slate-400 dark:hover:text-white uppercase tracking-wider transition-all">
      <span class="material-symbols-outlined text-sm">arrow_back</span>
      <span>Volver a la lista de cursos</span>
    </a>
  </div>

  <!-- Course Header Banner -->
  <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.03)] overflow-hidden transition-colors duration-300">
    <!-- Banner Image -->
    <div class="h-56 bg-slate-950 border-b border-slate-200 dark:border-slate-800 overflow-hidden relative">
      <img 
        *ngIf="curso.imagenPortada" 
        [src]="curso.imagenPortada" 
        [alt]="curso.nombre" 
        class="w-full h-full object-cover opacity-50">
      <div *ngIf="!curso.imagenPortada" class="w-full h-full bg-gradient-to-r from-slate-950 via-slate-900 to-slate-950 opacity-90"></div>

      <!-- Overlay Header Content -->
      <div class="absolute inset-0 p-8 flex flex-col justify-end text-white bg-gradient-to-t from-black/95 via-black/40 to-transparent">
        <div class="flex flex-wrap items-center gap-3">
          <span [ngClass]="getSubscriptionClass(curso.nivelesSuscripcion)" class="px-2.5 py-0.5 text-[9px] font-black uppercase tracking-wider rounded-none">
            {{ formatNiveles(curso.nivelesSuscripcion) }}
          </span>
          <span [ngClass]="curso.estado ? 'bg-emerald-500/20 text-emerald-300 border-emerald-500/30' : 'bg-red-500/20 text-red-350 border-red-500/30'" class="px-2.5 py-0.5 text-[9px] font-black uppercase tracking-wider border rounded-none">
            {{ curso.estado ? 'Activo' : 'Inactivo' }}
          </span>
        </div>
        <h1 class="text-2xl sm:text-3xl font-black mt-3 tracking-tight uppercase leading-none">{{ curso.nombre }}</h1>
        <p class="text-slate-300 text-xs mt-2 max-w-3xl leading-relaxed">{{ curso.descripcion }}</p>
      </div>
    </div>

    <!-- Actions Toolbar -->
    <div class="px-8 py-4 bg-slate-50 dark:bg-slate-800 flex flex-wrap justify-between items-center gap-4 border-t border-slate-100 dark:border-slate-800 transition-colors duration-300">
      <span class="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-wider">
        Administración Académica
      </span>
      <div class="flex flex-wrap gap-2.5">
        <button 
          *ngIf="!isDocente"
          (click)="openEditCourseModal()" 
          class="flex items-center gap-2 px-4 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 text-slate-700 dark:text-slate-300 font-bold text-xs uppercase tracking-wider transition-all rounded-none shadow-[2px_2px_0px_0px_rgba(0,0,0,0.03)] transition-colors duration-300">
          <span class="material-symbols-outlined text-sm">edit</span>
          <span>Editar Curso</span>
        </button>
        <button 
          *ngIf="activeTab === 'modulos'"
          (click)="openCreateModuloModal()" 
          class="flex items-center gap-2 px-4 py-2 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 hover:bg-slate-800 dark:hover:bg-slate-200 font-bold text-xs uppercase tracking-wider transition-all rounded-none shadow-[2px_2px_0px_0px_rgba(0,0,0,0.15)] transition-colors duration-300">
          <span class="material-symbols-outlined text-sm">add</span>
          <span>Agregar Módulo</span>
        </button>
        <button 
          *ngIf="activeTab === 'matriculas'"
          (click)="exportarMatriculasCSV()" 
          class="flex items-center gap-2 px-4 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 text-slate-700 dark:text-slate-300 font-bold text-xs uppercase tracking-wider transition-all rounded-none shadow-[2px_2px_0px_0px_rgba(0,0,0,0.03)] transition-colors duration-300">
          <span class="material-symbols-outlined text-sm">download</span>
          <span>Exportar CSV</span>
        </button>
        <button 
          *ngIf="activeTab === 'matriculas'"
          (click)="openMatriculaModal()" 
          class="flex items-center gap-2 px-4 py-2 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 hover:bg-slate-800 dark:hover:bg-slate-200 font-bold text-xs uppercase tracking-wider transition-all rounded-none shadow-[2px_2px_0px_0px_rgba(0,0,0,0.15)] transition-colors duration-300">
          <span class="material-symbols-outlined text-sm">person_add</span>
          <span>Matricular Alumno</span>
        </button>
      </div>
    </div>
  </div>

  <!-- Tab Navigation -->
  <div class="flex border-b border-slate-200 dark:border-slate-800 bg-white/50 dark:bg-slate-900/50 px-2 transition-colors duration-300">
    <button
      (click)="setTab('modulos')"
      [ngClass]="activeTab === 'modulos' ? 'border-b-2 border-slate-900 dark:border-b-white text-slate-900 dark:text-white' : 'border-b-2 border-transparent text-slate-500 dark:text-slate-400 hover:text-slate-800 dark:hover:text-slate-200'"
      class="flex items-center gap-2 px-5 py-3 text-[10px] font-black uppercase tracking-wider transition-all">
      <span class="material-symbols-outlined text-sm">view_module</span>
      <span>Módulos del Curso</span>
      <span [ngClass]="activeTab === 'modulos' ? 'bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900' : 'bg-slate-100 dark:bg-slate-800 text-slate-606 dark:text-slate-400'" class="px-1.5 py-0.5 text-[9px] font-black rounded-none transition-colors">{{ modulos.length }}</span>
    </button>
    <button
      *ngIf="!isDocente"
      (click)="setTab('matriculas')"
      [ngClass]="activeTab === 'matriculas' ? 'border-b-2 border-slate-900 dark:border-b-white text-slate-900 dark:text-white' : 'border-b-2 border-transparent text-slate-500 dark:text-slate-400 hover:text-slate-800 dark:hover:text-slate-200'"
      class="flex items-center gap-2 px-5 py-3 text-[10px] font-black uppercase tracking-wider transition-all">
      <span class="material-symbols-outlined text-sm">how_to_reg</span>
      <span>Alumnos Matriculados</span>
      <span [ngClass]="activeTab === 'matriculas' ? 'bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900' : 'bg-slate-100 dark:bg-slate-800 text-slate-606 dark:text-slate-400'" class="px-1.5 py-0.5 text-[9px] font-black rounded-none transition-colors">{{ matriculas.length }}</span>
    </button>
  </div>

  <!-- ===================== TAB: MÓDULOS ===================== -->
  <div *ngIf="activeTab === 'modulos'" class="space-y-6 animate-fadeIn">
    <!-- Empty State -->
    <div *ngIf="modulos.length === 0" class="border border-slate-200 dark:border-slate-800 p-16 bg-white dark:bg-slate-900 text-center rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.03)] transition-colors duration-300">
      <span class="material-symbols-outlined text-5xl text-slate-300 dark:text-slate-600 mb-3">folder_zip</span>
      <h3 class="text-xs font-black text-slate-800 dark:text-slate-200 uppercase tracking-wider">Sin Módulos</h3>
      <p class="text-xs text-slate-500 dark:text-slate-400 mt-1 max-w-sm mx-auto leading-relaxed">Este curso todavía no contiene módulos organizados. Haz click en "Agregar Módulo" para comenzar a estructurar el contenido.</p>
    </div>

    <!-- Accordion Modules List -->
    <div *ngIf="modulos.length > 0" class="space-y-4">
      <div 
        *ngFor="let modulo of modulos" 
        class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 rounded-none shadow-[3px_3px_0px_0px_rgba(15,23,42,0.02)] overflow-hidden transition-all duration-300">

        <!-- Accordion Header -->
        <div 
          (click)="toggleModuloExpansion(modulo.id)"
          class="p-4 sm:p-5 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3 cursor-pointer hover:bg-slate-50/50 dark:hover:bg-slate-800/50 select-none transition-colors border-l-4"
          [ngClass]="modulo.estado ? 'border-l-slate-900 dark:border-l-slate-100' : 'border-l-slate-300 dark:border-l-slate-700'">

          <div class="flex items-center gap-4">
            <!-- Position Badge -->
            <span class="w-9 h-9 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 font-black text-xs flex items-center justify-center rounded-none shadow-[2px_2px_0px_0px_rgba(0,0,0,0.1)] shrink-0">
              {{ modulo.orden | number:'2.0' }}
            </span>
            <div>
              <h3 class="font-black text-sm text-slate-900 dark:text-white uppercase tracking-tight">{{ modulo.nombre }}</h3>
              <p class="text-[11px] text-slate-500 dark:text-slate-400 line-clamp-1 mt-0.5 max-w-xl">{{ modulo.descripcion }}</p>
            </div>
          </div>

          <div class="flex items-center gap-3 w-full sm:w-auto justify-between sm:justify-end border-t sm:border-0 pt-2 sm:pt-0 border-slate-100 dark:border-slate-800">
            <!-- Info indicators -->
            <div class="flex items-center gap-3 text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">
              <span [ngClass]="modulo.estado ? 'text-emerald-700 bg-emerald-50 border border-emerald-200 dark:bg-emerald-950/30 dark:text-emerald-400 dark:border-emerald-900' : 'text-slate-500 bg-slate-50 border border-slate-200 dark:bg-slate-800 dark:text-slate-400 dark:border-slate-700'" class="px-2 py-0.5 text-[9px] font-black rounded-none">
                {{ modulo.estado ? 'Activo' : 'Inactivo' }}
              </span>
            </div>
            <!-- Expand Icon -->
            <span class="material-symbols-outlined text-slate-400 dark:text-slate-500 transition-transform duration-200" [ngClass]="expandedModuloId === modulo.id ? 'rotate-180 text-slate-900 dark:text-white' : ''">
              keyboard_arrow_down
            </span>
          </div>
        </div>

        <!-- Accordion Content Panel (Inline management) -->
        <div *ngIf="expandedModuloId === modulo.id" class="border-t border-slate-200 dark:border-slate-800 bg-slate-50/40 dark:bg-slate-800/20 p-5 sm:p-6 space-y-6 animate-fadeIn transition-colors duration-300">

          <div class="grid grid-cols-1 lg:grid-cols-2 gap-6">

            <!-- LEFT COLUMN: VIDEOS -->
            <div class="space-y-4">
              <div class="flex items-center justify-between border-b border-slate-200 dark:border-slate-800 pb-2">
                <h4 class="text-[10px] font-black text-slate-900 dark:text-white uppercase tracking-wider flex items-center gap-1.5">
                  <span class="material-symbols-outlined text-sm text-slate-600 dark:text-slate-400">videocam</span>
                  <span>Videos de Clases</span>
                </h4>
                <button 
                  (click)="$event.stopPropagation(); videoFormOpenMap[modulo.id] = !videoFormOpenMap[modulo.id]"
                  class="text-[9px] font-black text-indigo-600 dark:text-indigo-400 hover:text-indigo-950 dark:hover:text-indigo-300 uppercase tracking-wider flex items-center gap-1 transition-colors">
                  <span class="material-symbols-outlined text-xs">{{ videoFormOpenMap[modulo.id] ? 'close' : 'add' }}</span>
                  <span>{{ videoFormOpenMap[modulo.id] ? 'Cancelar' : 'Agregar Video' }}</span>
                </button>
              </div>

              <!-- Inline Add Video Form -->
              <div *ngIf="videoFormOpenMap[modulo.id]" class="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-4 space-y-3.5 shadow-[2px_2px_0px_0px_rgba(0,0,0,0.02)] animate-fadeIn transition-colors duration-300">
                <div class="grid grid-cols-1 sm:grid-cols-2 gap-3">
                  <div class="space-y-1">
                    <label class="block text-[8px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-wider">Título del Video *</label>
                    <input 
                      [(ngModel)]="nuevoVideoTitulo"
                      type="text" 
                      placeholder="Ej. Introducción Práctica"
                      class="w-full px-2.5 py-1.5 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-indigo-600 focus:border-indigo-600 transition-colors duration-300">
                  </div>
                  <div class="space-y-1">
                    <label class="block text-[8px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-wider">URL de YouTube *</label>
                    <input 
                      [(ngModel)]="nuevoVideoUrl"
                      type="text" 
                      placeholder="Ej. https://youtube.com/watch?v=..."
                      class="w-full px-2.5 py-1.5 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-indigo-600 focus:border-indigo-600 transition-colors duration-300">
                  </div>
                </div>
                <div class="space-y-1">
                  <label class="block text-[8px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-wider">Breve Descripción</label>
                  <textarea 
                    [(ngModel)]="nuevoVideoDesc"
                    rows="2" 
                    placeholder="Contenido clave de la lección..."
                    class="w-full px-2.5 py-1.5 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-indigo-600 focus:border-indigo-600 transition-colors duration-300"></textarea>
                </div>
                <div class="flex justify-end gap-2 pt-1">
                  <button 
                    (click)="videoFormOpenMap[modulo.id] = false"
                    class="px-3 py-1 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 font-bold text-[10px] uppercase tracking-wider hover:bg-slate-50 dark:hover:bg-slate-700 rounded-none transition-colors duration-300">
                    Cancelar
                  </button>
                  <button 
                    (click)="agregarVideoInline(modulo.id)"
                    [disabled]="isAddingVideo"
                    class="px-3 py-1 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 font-bold text-[10px] uppercase tracking-wider hover:bg-slate-800 dark:hover:bg-slate-200 rounded-none disabled:opacity-50 transition-colors duration-300">
                    {{ isAddingVideo ? 'Guardando...' : 'Guardar Video' }}
                  </button>
                </div>
              </div>

              <!-- Videos List -->
              <div class="space-y-2.5">
                <div *ngIf="!videosMap[modulo.id] || videosMap[modulo.id].length === 0" class="text-center py-6 text-slate-400 dark:text-slate-500 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800">
                  <span class="material-symbols-outlined text-3xl text-slate-300 dark:text-slate-700">video_library</span>
                  <p class="text-[10px] mt-1 font-medium">No hay videos en este módulo.</p>
                </div>
                <div 
                  *ngFor="let video of videosMap[modulo.id]" 
                  class="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-3 flex justify-between items-center gap-3 hover:border-slate-300 dark:hover:border-slate-700 transition-colors duration-350">
                  <div class="overflow-hidden">
                    <span class="text-[8px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-wider block">Lección</span>
                    <h5 class="font-bold text-slate-800 dark:text-slate-200 text-xs truncate max-w-sm uppercase mt-0.5">{{ video.titulo }}</h5>
                    <p class="text-[10px] text-slate-455 dark:text-slate-500 truncate font-mono mt-0.5">{{ video.youtubeUrl }}</p>
                  </div>
                  <div class="flex items-center gap-1.5 shrink-0">
                    <button 
                      (click)="toggleVideoEstadoInline(modulo.id, video)"
                      [title]="video.estado ? 'Desactivar' : 'Activar'"
                      [ngClass]="video.estado ? 'border-red-200 dark:border-red-900/60 text-red-600 dark:text-red-400 hover:bg-red-50/50 dark:hover:bg-red-950/20' : 'border-emerald-200 dark:border-emerald-900/60 text-emerald-600 dark:text-emerald-400 hover:bg-emerald-50/50 dark:hover:bg-emerald-950/20'"
                      class="p-1.5 border rounded-none transition-colors">
                      <span class="material-symbols-outlined text-xs block">
                        {{ video.estado ? 'block' : 'check_circle' }}
                      </span>
                    </button>
                    <!-- External Link -->
                    <a 
                      [href]="video.youtubeUrl" 
                      target="_blank"
                      title="Ver en YouTube"
                      class="p-1.5 border border-slate-200 dark:border-slate-700 hover:border-slate-800 dark:hover:border-slate-300 text-slate-500 dark:text-slate-400 rounded-none transition-colors">
                      <span class="material-symbols-outlined text-xs block">open_in_new</span>
                    </a>
                  </div>
                </div>
              </div>
            </div>

            <!-- RIGHT COLUMN: MATERIALS -->
            <div class="space-y-4">
              <div class="flex items-center justify-between border-b border-slate-200 dark:border-slate-800 pb-2">
                <h4 class="text-[10px] font-black text-slate-900 dark:text-white uppercase tracking-wider flex items-center gap-1.5">
                  <span class="material-symbols-outlined text-sm text-slate-600 dark:text-slate-400">description</span>
                  <span>Materiales de Apoyo</span>
                </h4>
                <button 
                  (click)="$event.stopPropagation(); materialFormOpenMap[modulo.id] = !materialFormOpenMap[modulo.id]"
                  class="text-[9px] font-black text-indigo-600 dark:text-indigo-400 hover:text-indigo-950 dark:hover:text-indigo-300 uppercase tracking-wider flex items-center gap-1 transition-colors">
                  <span class="material-symbols-outlined text-xs">{{ materialFormOpenMap[modulo.id] ? 'close' : 'add' }}</span>
                  <span>{{ materialFormOpenMap[modulo.id] ? 'Cancelar' : 'Subir Archivo' }}</span>
                </button>
              </div>

              <!-- Inline Upload File Form -->
              <div *ngIf="materialFormOpenMap[modulo.id]" class="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-4 space-y-3.5 shadow-[2px_2px_0px_0px_rgba(0,0,0,0.02)] animate-fadeIn transition-colors duration-300">
                <div class="space-y-1">
                  <label class="block text-[8px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-wider">Nombre del Recurso *</label>
                  <input 
                    [(ngModel)]="nuevoMaterialNombre"
                    type="text" 
                    placeholder="Ej. Guía Práctica Excel"
                    class="w-full px-2.5 py-1.5 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-indigo-600 focus:border-indigo-600 transition-colors duration-300">
                </div>
                <div class="space-y-1">
                  <label class="block text-[8px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-wider">Seleccionar Archivo *</label>
                  <div 
                    [ngClass]="nuevoMaterialFile ? 'border-indigo-500 bg-indigo-50/10' : 'border-slate-300 dark:border-slate-700 bg-slate-50/50 dark:bg-slate-800/50'"
                    class="border-2 border-dashed p-4 text-center hover:bg-slate-100 dark:hover:bg-slate-800 transition-all relative rounded-none select-none cursor-pointer group">
                    <input 
                      type="file" 
                      (change)="onInlineFileSelected($event)"
                      accept=".pdf,.doc,.docx,.jpg,.jpeg,.png"
                      class="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10">
                    <div class="space-y-1.5">
                      <span [ngClass]="nuevoMaterialFile ? 'text-indigo-600' : 'text-slate-400 dark:text-slate-500 group-hover:text-slate-600'" class="material-symbols-outlined text-2xl transition-colors">cloud_upload</span>
                      <div class="text-[11px] font-bold text-slate-700 dark:text-slate-300 max-w-xs mx-auto truncate">
                        {{ nuevoMaterialFile ? nuevoMaterialFile.name : 'Seleccione o arrastre un archivo' }}
                      </div>
                      <p class="text-[8px] text-slate-400 dark:text-slate-500">PDF, DOC, DOCX, JPG, PNG (Max. 10MB)</p>
                    </div>
                  </div>
                </div>
                <div class="flex justify-end gap-2 pt-1">
                  <button 
                    (click)="materialFormOpenMap[modulo.id] = false"
                    class="px-3 py-1 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 font-bold text-[10px] uppercase tracking-wider hover:bg-slate-50 dark:hover:bg-slate-700 rounded-none transition-colors duration-300">
                    Cancelar
                  </button>
                  <button 
                    (click)="subirMaterialInline(modulo.id)"
                    [disabled]="isUploadingMaterial"
                    class="px-3 py-1 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 font-bold text-[10px] uppercase tracking-wider hover:bg-slate-800 dark:hover:bg-slate-200 rounded-none disabled:opacity-50 transition-colors duration-300">
                    {{ isUploadingMaterial ? 'Subiendo...' : 'Subir Archivo' }}
                  </button>
                </div>
              </div>

              <!-- Materials List -->
              <div class="space-y-2.5">
                <div *ngIf="!materialesMap[modulo.id] || materialesMap[modulo.id].length === 0" class="text-center py-6 text-slate-400 dark:text-slate-500 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800">
                  <span class="material-symbols-outlined text-3xl text-slate-300 dark:text-slate-700">folder_open</span>
                  <p class="text-[10px] mt-1 font-medium">No hay materiales cargados en este módulo.</p>
                </div>
                <div 
                  *ngFor="let mat of materialesMap[modulo.id]" 
                  class="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-3 flex justify-between items-center gap-3 hover:border-slate-300 dark:hover:border-slate-700 transition-colors duration-300">
                  <div class="overflow-hidden flex items-center gap-2">
                    <span class="material-symbols-outlined text-slate-400 dark:text-slate-500 text-base shrink-0">{{ getFileIcon(mat.tipoArchivo) }}</span>
                    <div>
                      <h5 class="font-bold text-slate-800 dark:text-slate-200 text-xs truncate max-w-sm uppercase">{{ mat.nombre }}</h5>
                      <div class="flex items-center gap-2 mt-0.5">
                        <span 
                          [ngClass]="{
                            'bg-rose-50 dark:bg-rose-950/30 text-rose-700 dark:text-rose-400 border-rose-200 dark:border-rose-900': getCleanFileType(mat.tipoArchivo) === 'PDF',
                            'bg-blue-50 dark:bg-blue-950/30 text-blue-700 dark:text-blue-450 border-blue-200 dark:border-blue-900': getCleanFileType(mat.tipoArchivo) === 'DOCX' || getCleanFileType(mat.tipoArchivo) === 'DOC',
                            'bg-emerald-50 dark:bg-emerald-950/30 text-emerald-700 dark:text-emerald-400 border-emerald-200 dark:border-emerald-900': getCleanFileType(mat.tipoArchivo) === 'JPG' || getCleanFileType(mat.tipoArchivo) === 'PNG',
                            'bg-slate-50 dark:bg-slate-800 text-slate-700 dark:text-slate-400 border-slate-200 dark:border-slate-700': getCleanFileType(mat.tipoArchivo) !== 'PDF' && getCleanFileType(mat.tipoArchivo) !== 'DOCX' && getCleanFileType(mat.tipoArchivo) !== 'DOC' && getCleanFileType(mat.tipoArchivo) !== 'JPG' && getCleanFileType(mat.tipoArchivo) !== 'PNG'
                          }"
                          class="px-1.5 py-0.2 border text-[8px] font-black uppercase tracking-wider rounded-none shrink-0">
                          {{ getCleanFileType(mat.tipoArchivo) }}
                        </span>
                        <span class="text-[9px] text-slate-400 dark:text-slate-500 font-mono">{{ formatBytes(mat.pesoBytes) }}</span>
                      </div>
                    </div>
                  </div>
                  <div class="flex items-center gap-1.5 shrink-0">
                    <button 
                      (click)="toggleMaterialEstadoInline(modulo.id, mat)"
                      [title]="mat.estado ? 'Desactivar' : 'Activar'"
                      [ngClass]="mat.estado ? 'border-red-200 dark:border-red-900/60 text-red-600 dark:text-red-400 hover:bg-red-50/50 dark:hover:bg-red-950/20' : 'border-emerald-205 dark:border-emerald-900/60 text-emerald-650 dark:text-emerald-400 hover:bg-emerald-50/50 dark:hover:bg-emerald-950/20'"
                      class="p-1.5 border rounded-none transition-colors">
                      <span class="material-symbols-outlined text-xs block">
                        {{ mat.estado ? 'block' : 'check_circle' }}
                      </span>
                    </button>
                    <!-- Download Link -->
                    <button
                      (click)="descargarMaterial(mat)"
                      title="Descargar Archivo"
                      class="p-1.5 border border-slate-200 dark:border-slate-700 hover:border-slate-800 dark:hover:border-slate-300 text-slate-500 dark:text-slate-400 rounded-none transition-colors">
                      <span class="material-symbols-outlined text-xs block">download</span>
                    </button>
                  </div>
                </div>
              </div>
            </div>

          </div>

          <!-- Module Configuration Toolbar (Footer of the expanded panel) -->
          <div class="flex items-center justify-end gap-2.5 pt-4 border-t border-slate-200 dark:border-slate-800">
            <span class="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-wider mr-auto">
              Configuración del Módulo:
            </span>
            <button 
              (click)="openEditModuloModal(modulo)" 
              class="flex items-center gap-1.5 px-3 py-1.5 border border-slate-300 dark:border-slate-700 hover:border-slate-800 dark:hover:border-slate-300 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 hover:text-slate-900 dark:hover:text-white font-bold text-[10px] uppercase tracking-wider transition-all rounded-none shadow-[1px_1px_0px_0px_rgba(0,0,0,0.02)] transition-colors duration-300">
              <span class="material-symbols-outlined text-xs">edit</span>
              <span>Editar</span>
            </button>
            <button 
              (click)="toggleModuloEstado(modulo)" 
              [ngClass]="modulo.estado ? 'border-red-205 dark:border-red-900/60 text-red-600 dark:text-red-400 hover:bg-red-50/50 dark:hover:bg-red-950/20' : 'border-emerald-205 dark:border-emerald-900/60 text-emerald-600 dark:text-emerald-400 hover:bg-emerald-50/50 dark:hover:bg-emerald-950/20'"
              class="flex items-center gap-1.5 px-3 py-1.5 border font-bold text-[10px] uppercase tracking-wider transition-all rounded-none shadow-[1px_1px_0px_0px_rgba(0,0,0,0.02)] transition-colors duration-300">
              <span class="material-symbols-outlined text-xs">{{ modulo.estado ? 'block' : 'check_circle' }}</span>
              <span>{{ modulo.estado ? 'Desactivar' : 'Activar' }}</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  </div>

  <!-- ===================== TAB: MATRÍCULAS ===================== -->
  <div *ngIf="activeTab === 'matriculas'" class="animate-fadeIn">
    <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.03)] overflow-hidden transition-colors duration-300">
      <!-- Table -->
      <div class="overflow-x-auto">
        <table class="w-full text-left border-collapse text-xs">
          <thead>
            <tr class="border-b border-slate-200 dark:border-slate-800 bg-slate-100/60 dark:bg-slate-800/40 text-slate-700 dark:text-slate-300 font-bold uppercase tracking-wider text-[10px] transition-colors duration-300">
              <th class="p-4">Alumno</th>
              <th class="p-4">Correo Electrónico</th>
              <th class="p-4">Fecha de Inscripción</th>
              <th class="p-4">Estado</th>
              <th class="p-4 text-right">Acciones</th>
            </tr>
          </thead>
          <tbody class="divide-y divide-slate-100 dark:divide-slate-800">
            <!-- Empty State -->
            <tr *ngIf="matriculas.length === 0">
              <td colspan="5" class="p-12 text-center text-slate-400 dark:text-slate-500">
                <span class="material-symbols-outlined text-4xl mb-2 text-slate-300 dark:text-slate-700">group_off</span>
                <p class="font-medium text-xs">No hay alumnos matriculados en este curso.</p>
                <p class="text-[10px] text-slate-400 dark:text-slate-500 mt-1">Haz click en "Matricular Alumno" para agregar estudiantes.</p>
              </td>
            </tr>
            <!-- Rows -->
            <tr *ngFor="let matricula of matriculas" class="hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-colors duration-200">
              <td class="p-4">
                <div class="flex items-center gap-3">
                  <div class="w-8 h-8 bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-800 dark:text-slate-200 flex items-center justify-center font-black text-[10px] rounded-none">
                    {{ matricula.alumnoNombres.charAt(0) }}{{ matricula.alumnoApellidos.charAt(0) }}
                  </div>
                  <span class="font-bold text-slate-900 dark:text-white">{{ matricula.alumnoNombres }} {{ matricula.alumnoApellidos }}</span>
                </div>
              </td>
              <td class="p-4 text-slate-600 dark:text-slate-400 font-mono text-[11px]">
                {{ matricula.alumnoCorreo }}
              </td>
              <td class="p-4 text-slate-600 dark:text-slate-400">
                {{ matricula.fechaMatricula | date:'dd/MM/yyyy HH:mm' }}
              </td>
              <td class="p-4">
                <span [ngClass]="matricula.estado ? 'bg-emerald-50 text-emerald-700 border-emerald-200 dark:bg-emerald-950/30 dark:text-emerald-400 dark:border-emerald-900' : 'bg-red-50 text-red-700 border-red-200 dark:bg-red-950/30 dark:text-red-400 dark:border-red-900'" class="px-2.5 py-1 text-[9px] font-black uppercase tracking-wider border rounded-none">
                  {{ matricula.estado ? 'ACTIVO' : 'BAJA' }}
                </span>
              </td>
              <td class="p-4 text-right">
                <button 
                  (click)="toggleMatriculaEstado(matricula)" 
                  [title]="matricula.estado ? 'Dar de Baja' : 'Reactivar'"
                  [ngClass]="matricula.estado ? 'border-red-200 dark:border-red-900/60 text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-950/20' : 'border-emerald-200 dark:border-emerald-900/60 text-emerald-600 dark:text-emerald-400 hover:bg-emerald-50 dark:hover:bg-emerald-950/20'"
                  class="p-1.5 border rounded-none transition-all shadow-[1px_1px_0px_0px_rgba(0,0,0,0.03)]">
                  <span class="material-symbols-outlined text-base block">
                    {{ matricula.estado ? 'person_remove' : 'person_add' }}
                  </span>
                </button>
              </td>
            </tr>
          </tbody>
        </table>
      </div>
      <!-- Footer -->
      <div class="p-4 border-t border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-800 flex items-center justify-between transition-colors duration-300">
        <span class="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-wider">
          Total: {{ matriculas.length }} alumnos inscritos
        </span>
      </div>
    </div>
  </div>

  <!-- ===================== MODAL: MATRICULAR ALUMNO ===================== -->
  <div *ngIf="showMatriculaModal" class="fixed inset-0 bg-slate-900/60 dark:bg-slate-950/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
    <div class="w-full max-w-md bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-800 shadow-2xl rounded-none overflow-hidden relative transition-colors duration-300">
      <!-- Modal Header -->
      <div class="px-6 py-4 border-b border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-800 flex items-center justify-between transition-colors duration-300">
        <h3 class="text-sm font-black text-slate-900 dark:text-white uppercase tracking-wider">Matricular Alumno</h3>
        <button (click)="closeMatriculaModal()" class="text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300 flex">
          <span class="material-symbols-outlined text-lg">close</span>
        </button>
      </div>

      <div class="p-6 space-y-5">
        <!-- Error -->
        <div *ngIf="matriculaErrorMsg" class="flex items-start gap-2 bg-red-50 dark:bg-red-950/30 border border-red-200 dark:border-red-900 text-red-800 dark:text-red-300 p-3 rounded-none text-[11px] font-semibold animate-fadeIn transition-colors duration-300">
          <span class="material-symbols-outlined text-red-600 text-base shrink-0">warning</span>
          <span>{{ matriculaErrorMsg }}</span>
        </div>

        <!-- Course Name (ReadOnly Badge style) -->
        <div class="bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-800 p-3.5 transition-colors duration-300">
          <span class="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-wider block">Curso de Destino</span>
          <span class="text-xs font-bold text-slate-900 dark:text-white uppercase mt-0.5 block">{{ curso.nombre }}</span>
        </div>

        <!-- Student Select -->
        <div class="space-y-1.5">
          <label class="block text-[9px] font-black text-slate-700 dark:text-slate-300 uppercase tracking-widest">Seleccionar Alumno *</label>
          <select 
            [(ngModel)]="selectedAlumnoId"
            class="w-full px-3 py-2.5 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-indigo-600 focus:border-indigo-600 transition-colors duration-300">
            <option [ngValue]="null" disabled>-- Seleccione un alumno de la lista --</option>
            <option *ngFor="let alumno of alumnosDisponibles" [ngValue]="alumno.id">
              {{ alumno.nombres }} {{ alumno.apellidos }} — {{ alumno.correo }}
            </option>
          </select>
          <p *ngIf="alumnosDisponibles.length === 0" class="text-[10px] text-slate-500 dark:text-slate-400 font-medium">No hay alumnos disponibles para matricular en este curso.</p>
        </div>

        <!-- Buttons -->
        <div class="pt-4 border-t border-slate-100 dark:border-slate-800 flex justify-end gap-3">
          <button 
            type="button" 
            (click)="closeMatriculaModal()" 
            class="px-4 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-305 font-bold text-xs uppercase tracking-wider hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors rounded-none shadow-[2px_2px_0px_0px_rgba(0,0,0,0.03)]">
            Cancelar
          </button>
          <button 
            (click)="onMatriculaSubmit()"
            [disabled]="!selectedAlumnoId || isMatriculaSubmitting" 
            class="px-4 py-2 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 font-bold text-xs uppercase tracking-wider hover:bg-slate-800 dark:hover:bg-slate-200 transition-colors rounded-none disabled:opacity-55 shadow-[2px_2px_0px_0px_rgba(0,0,0,0.15)]">
            {{ isMatriculaSubmitting ? 'Procesando...' : 'Matricular' }}
          </button>
        </div>
      </div>
    </div>
  </div>

  <!-- ===================== MODAL: CREAR/EDITAR MÓDULO ===================== -->
  <div *ngIf="showModuloModal" class="fixed inset-0 bg-slate-900/60 dark:bg-slate-950/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
    <div class="w-full max-w-md bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-800 shadow-2xl rounded-none overflow-hidden relative transition-colors duration-300">
      <div class="px-6 py-4 border-b border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-800 flex items-center justify-between transition-colors duration-300">
        <h3 class="text-sm font-black text-slate-900 dark:text-white uppercase tracking-wider">
          {{ isEditModuloMode ? 'Editar Módulo' : 'Registrar Nuevo Módulo' }}
        </h3>
        <button (click)="closeModuloModal()" class="text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300 flex">
          <span class="material-symbols-outlined text-lg">close</span>
        </button>
      </div>

      <form [formGroup]="moduloForm" (ngSubmit)="onModuloSubmit()" class="p-6 space-y-5">
        <!-- Error alert -->
        <div *ngIf="moduloErrorMsg" class="flex items-start gap-2 bg-red-50 dark:bg-red-950/30 border border-red-200 dark:border-red-900 text-red-800 dark:text-red-300 p-3 rounded-none text-[11px] font-semibold animate-fadeIn transition-colors duration-300">
          <span class="material-symbols-outlined text-red-600 text-base shrink-0">warning</span>
          <span>{{ moduloErrorMsg }}</span>
        </div>

        <!-- Nombre del Módulo -->
        <div class="space-y-1">
          <label class="block text-[9px] font-black text-slate-700 dark:text-slate-300 uppercase tracking-widest">Nombre del Módulo *</label>
          <input 
            formControlName="nombre" 
            type="text" 
            class="w-full px-3 py-2.5 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-indigo-600 focus:border-indigo-600 transition-colors duration-300"
            placeholder="Ej. Fundamentos de Análisis de Datos">
          <p *ngIf="moduloForm.get('nombre')?.hasError('required') && moduloForm.get('nombre')?.touched" class="text-[9px] font-bold text-red-600 mt-1">El nombre es obligatorio.</p>
          <p *ngIf="moduloForm.get('nombre')?.hasError('minlength') && moduloForm.get('nombre')?.touched" class="text-[9px] font-bold text-red-600 mt-1">Debe tener al menos 3 caracteres.</p>
        </div>

        <!-- Descripción -->
        <div class="space-y-1">
          <label class="block text-[9px] font-black text-slate-700 dark:text-slate-300 uppercase tracking-widest">Descripción *</label>
          <textarea 
            formControlName="descripcion" 
            rows="3" 
            class="w-full px-3 py-2.5 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-indigo-600 focus:border-indigo-655 transition-colors duration-300"
            placeholder="Escribe el resumen del temario de este módulo..."></textarea>
          <p *ngIf="moduloForm.get('descripcion')?.hasError('required') && moduloForm.get('descripcion')?.touched" class="text-[9px] font-bold text-red-600 mt-1">La descripción es obligatoria.</p>
          <p *ngIf="moduloForm.get('descripcion')?.hasError('minlength') && moduloForm.get('descripcion')?.touched" class="text-[9px] font-bold text-red-600 mt-1">Debe tener al menos 10 caracteres.</p>
        </div>

        <!-- Orden y Estado -->
        <div class="grid grid-cols-2 gap-4">
          <div class="space-y-1">
            <label class="block text-[9px] font-black text-slate-700 dark:text-slate-300 uppercase tracking-widest">Orden / Posición *</label>
            <input 
              formControlName="orden" 
              type="number" 
              class="w-full px-3 py-2.5 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-indigo-600 focus:border-indigo-600 transition-colors duration-300">
            <p *ngIf="moduloForm.get('orden')?.hasError('required') && moduloForm.get('orden')?.touched" class="text-[9px] font-bold text-red-600 mt-1">El orden es requerido.</p>
            <p *ngIf="moduloForm.get('orden')?.hasError('min') && moduloForm.get('orden')?.touched" class="text-[9px] font-bold text-red-600 mt-1">El orden mínimo es 1.</p>
            <p *ngIf="moduloForm.get('orden')?.hasError('max') && moduloForm.get('orden')?.touched" class="text-[9px] font-bold text-red-600 mt-1">El orden máximo es 999.</p>
          </div>
          <div class="space-y-1">
            <label class="block text-[9px] font-black text-slate-700 dark:text-slate-300 uppercase tracking-widest">Estado</label>
            <select 
              formControlName="estado" 
              class="w-full px-3 py-2.5 border border-slate-355 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-indigo-600 focus:border-indigo-600 transition-colors duration-300">
              <option [ngValue]="true">ACTIVO</option>
              <option [ngValue]="false">INACTIVO</option>
            </select>
          </div>
        </div>

        <!-- Action Buttons -->
        <div class="pt-4 border-t border-slate-100 dark:border-slate-800 flex justify-end gap-3">
          <button 
            type="button" 
            (click)="closeModuloModal()" 
            class="px-4 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-305 font-bold text-xs uppercase tracking-wider hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors rounded-none shadow-[2px_2px_0px_0px_rgba(0,0,0,0.03)]">
            Cancelar
          </button>
          <button 
            type="submit" 
            [disabled]="moduloForm.invalid || isModuloSubmitting" 
            class="px-4 py-2 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 font-bold text-xs uppercase tracking-wider hover:bg-slate-800 dark:hover:bg-slate-200 transition-colors rounded-none disabled:opacity-55 shadow-[2px_2px_0px_0px_rgba(0,0,0,0.15)]">
            {{ isModuloSubmitting ? 'Guardando...' : 'Guardar Módulo' }}
          </button>
        </div>
      </form>
    </div>
  </div>

  <!-- ===================== MODAL: EDITAR CURSO ===================== -->
  <div *ngIf="showEditCourseModal" class="fixed inset-0 bg-slate-900/60 dark:bg-slate-950/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
    <div class="w-full max-w-lg bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-800 shadow-2xl rounded-none overflow-hidden relative transition-colors duration-300">
      <div class="px-6 py-4 border-b border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-800 flex items-center justify-between transition-colors duration-300">
        <h3 class="text-sm font-black text-slate-900 dark:text-white uppercase tracking-wider">Modificar Curso</h3>
        <button (click)="closeEditCourseModal()" class="text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300 flex">
          <span class="material-symbols-outlined text-lg">close</span>
        </button>
      </div>

      <form [formGroup]="courseForm" (ngSubmit)="onCourseSubmit()" class="p-6 space-y-5">
        <div *ngIf="courseErrorMsg" class="flex items-start gap-2 bg-red-50 dark:bg-red-950/30 border border-red-200 dark:border-red-900 text-red-800 dark:text-red-300 p-3 rounded-none text-[11px] font-semibold animate-fadeIn transition-colors duration-300">
          <span class="material-symbols-outlined text-red-600 text-base shrink-0">warning</span>
          <span>{{ courseErrorMsg }}</span>
        </div>

        <!-- Nombre -->
        <div class="space-y-1">
          <label class="block text-[9px] font-black text-slate-700 dark:text-slate-300 uppercase tracking-widest">Nombre del Curso *</label>
          <input 
            formControlName="nombre" 
            type="text" 
            class="w-full px-3 py-2.5 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-indigo-600 focus:border-indigo-600 transition-colors duration-300">
          <p *ngIf="courseForm.get('nombre')?.hasError('required') && courseForm.get('nombre')?.touched" class="text-[9px] font-bold text-red-600 mt-1">El nombre del curso es requerido.</p>
          <p *ngIf="courseForm.get('nombre')?.hasError('minlength') && courseForm.get('nombre')?.touched" class="text-[9px] font-bold text-red-600 mt-1">Mínimo 3 caracteres.</p>
        </div>

        <!-- Descripción -->
        <div class="space-y-1">
          <label class="block text-[9px] font-black text-slate-700 dark:text-slate-300 uppercase tracking-widest">Descripción del Programa *</label>
          <textarea 
            formControlName="descripcion" 
            rows="3" 
            class="w-full px-3 py-2.5 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-indigo-600 focus:border-indigo-655 transition-colors duration-300"></textarea>
          <p *ngIf="courseForm.get('descripcion')?.hasError('required') && courseForm.get('descripcion')?.touched" class="text-[9px] font-bold text-red-600 mt-1">La descripción es requerida.</p>
          <p *ngIf="courseForm.get('descripcion')?.hasError('minlength') && courseForm.get('descripcion')?.touched" class="text-[9px] font-bold text-red-600 mt-1">Mínimo 10 caracteres.</p>
        </div>

        <!-- Imagen URL -->
        <div class="space-y-1">
          <label class="block text-[9px] font-black text-slate-700 dark:text-slate-300 uppercase tracking-widest">URL Imagen de Portada</label>
          <input 
            formControlName="imagenPortada" 
            type="text" 
            class="w-full px-3 py-2.5 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-indigo-600 focus:border-indigo-600 transition-colors duration-300"
            placeholder="Ej. https://images.unsplash.com/...">
          <p *ngIf="courseForm.get('imagenPortada')?.hasError('pattern') && courseForm.get('imagenPortada')?.touched" class="text-[9px] font-bold text-red-600 mt-1">Debe ser una dirección URL válida (ej. http:// o https://).</p>

          <!-- Image preview thumbnail -->
          <div *ngIf="courseForm.get('imagenPortada')?.value && courseForm.get('imagenPortada')?.valid" class="mt-2 w-full h-24 border border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-900 flex items-center justify-center overflow-hidden transition-colors duration-300">
            <img [src]="courseForm.get('imagenPortada')?.value" class="w-full h-full object-cover">
          </div>
        </div>

        <div class="grid grid-cols-1 md:grid-cols-2 gap-4">
          <!-- Subscription Access (Clickable buttons style) -->
          <div class="space-y-2">
            <label class="block text-[9px] font-black text-slate-700 dark:text-slate-300 uppercase tracking-widest">Acceso de Planes *</label>
            <div class="flex flex-col gap-1.5 p-2 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-800 transition-colors duration-300">
              <button 
                type="button" 
                (click)="toggleNivel(1)" 
                [ngClass]="isNivelSelected(1) ? 'bg-indigo-50 dark:bg-indigo-950/40 border-indigo-655 dark:border-indigo-500 text-indigo-955 dark:text-indigo-200 font-bold' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'"
                class="w-full py-2 border text-center transition-all text-[10px] uppercase font-bold flex items-center justify-center gap-1 rounded-none">
                <span class="material-symbols-outlined text-xs">{{ isNivelSelected(1) ? 'check_box' : 'check_box_outline_blank' }}</span>
                <span>Básico</span>
              </button>
              <button 
                type="button" 
                (click)="toggleNivel(2)" 
                [ngClass]="isNivelSelected(2) ? 'bg-indigo-50 dark:bg-indigo-950/40 border-indigo-655 dark:border-indigo-500 text-indigo-955 dark:text-indigo-200 font-bold' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'"
                class="w-full py-2 border text-center transition-all text-[10px] uppercase font-bold flex items-center justify-center gap-1 rounded-none">
                <span class="material-symbols-outlined text-xs">{{ isNivelSelected(2) ? 'check_box' : 'check_box_outline_blank' }}</span>
                <span>Intermedio</span>
              </button>
              <button 
                type="button" 
                (click)="toggleNivel(3)" 
                [ngClass]="isNivelSelected(3) ? 'bg-indigo-50 dark:bg-indigo-950/40 border-indigo-655 dark:border-indigo-500 text-indigo-955 dark:text-indigo-200 font-bold' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'"
                class="w-full py-2 border text-center transition-all text-[10px] uppercase font-bold flex items-center justify-center gap-1 rounded-none">
                <span class="material-symbols-outlined text-xs">{{ isNivelSelected(3) ? 'check_box' : 'check_box_outline_blank' }}</span>
                <span>Premium</span>
              </button>
            </div>
          </div>

          <!-- Estado -->
          <div class="space-y-1">
            <label class="block text-[9px] font-black text-slate-700 dark:text-slate-300 uppercase tracking-widest">Estado</label>
            <select 
              formControlName="estado" 
              class="w-full px-3 py-2.5 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-indigo-600 focus:border-indigo-600 transition-colors duration-300">
              <option [ngValue]="true">ACTIVO</option>
              <option [ngValue]="false">INACTIVO</option>
            </select>
          </div>
        </div>

        <div class="pt-4 border-t border-slate-100 dark:border-slate-800 flex justify-end gap-3">
          <button 
            type="button" 
            (click)="closeEditCourseModal()" 
            class="px-4 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-305 font-bold text-xs uppercase tracking-wider hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors rounded-none shadow-[2px_2px_0px_0px_rgba(0,0,0,0.03)]">
            Cancelar
          </button>
          <button 
            type="submit" 
            [disabled]="courseForm.invalid || isCourseSubmitting" 
            class="px-4 py-2 bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900 font-bold text-xs uppercase tracking-wider hover:bg-slate-800 dark:hover:bg-slate-200 transition-colors rounded-none disabled:opacity-55 shadow-[2px_2px_0px_0px_rgba(0,0,0,0.15)]">
            {{ isCourseSubmitting ? 'Guardando...' : 'Guardar Cambios' }}
          </button>
        </div>
      </form>
    </div>
  </div>

  <!-- Confirm modal -->
  <app-confirm-modal
    [visible]="showConfirmModal"
    [type]="confirmModalType"
    [title]="confirmModalTitle"
    [message]="confirmModalMessage"
    confirmText="Confirmar"
    (onConfirm)="confirmAction()"
    (onCancel)="showConfirmModal = false">
  </app-confirm-modal>

</div>
